// Lee la config desde Supabase (inyectada en nodo anterior)
// y procesa cada contrato para determinar si hay que notificar

const contratos = $input.first().json;
const lista = Array.isArray(contratos) ? contratos
  : (contratos?.contracts ?? contratos?.data ?? []);

const hoy = new Date();
hoy.setHours(0,0,0,0);

const candidatos = [];

for (const c of lista) {
  const fechaVencStr = c.due_date || c.expiration_date || c.next_due_date || "";
  if (!fechaVencStr) continue;

  const fechaVenc = new Date(fechaVencStr);
  fechaVenc.setHours(0,0,0,0);

  const diasVencido = Math.floor((hoy - fechaVenc) / (1000 * 60 * 60 * 24));
  const estado      = c.state || c.status || "";
  const deuda       = parseFloat(c.balance || c.debt || c.amount_due || 0);
  const tel         = c.subscriber?.phone || c.phone || "";
  const nombre      = c.subscriber?.name  || c.name  || "";

  // Recordatorio 1 (default: día +2)
  if (diasVencido === 2 && deuda > 0 && estado !== "disabled") {
    candidatos.push({ contrato: c, tipo: "recordatorio_1", diasVencido, deuda, tel, nombre });
  }
  // Recordatorio 2 (default: día +5)
  else if (diasVencido === 5 && deuda > 0) {
    candidatos.push({ contrato: c, tipo: "recordatorio_2", diasVencido, deuda, tel, nombre });
  }
  // Recordatorio 3 (default: día +7)
  else if (diasVencido === 7 && deuda > 0) {
    candidatos.push({ contrato: c, tipo: "recordatorio_3", diasVencido, deuda, tel, nombre });
  }
  // Suspensión
  else if (estado === "disabled" && deuda > 0) {
    candidatos.push({ contrato: c, tipo: "suspension", diasVencido, deuda, tel, nombre });
  }
}

return candidatos.map(c => ({ json: c }));

// Verificar si sigue con deuda después del chequeo en tiempo real
const contratoActual  = $input.first().json;
const candidato       = $('evaluar-candidatos').item.json;

const deudaActual  = parseFloat(contratoActual.balance || contratoActual.debt || contratoActual.amount_due || 0);
const estadoActual = contratoActual.state || contratoActual.status || "";

// Normalizar teléfono peruano
let tel = candidato.tel || "";
tel = tel.replace(/\D/g, "");
if (tel && !tel.startsWith("51")) tel = "51" + tel;

if (deudaActual <= 0) {
  return [{ json: { ...candidato, accion: "saltado_pago", tel, deudaActual } }];
}

if (candidato.tipo === "suspension" && estadoActual !== "disabled") {
  return [{ json: { ...candidato, accion: "saltado_estado", tel, deudaActual } }];
}

return [{ json: { ...candidato, accion: "enviar", tel, deudaActual } }];

// Construir payload WhatsApp según tipo de mensaje
const d = $input.first().json;

// ---- CONFIGURA AQUÍ ----
const PHONE_NUMBER_ID = "TU_PHONE_NUMBER_ID_DIM";  // Phone Number ID de DIM en Meta
const WABA_TOKEN      = "TU_TOKEN_PERMANENTE_DIM";  // Token permanente DIM
// -------------------------

const plantillas = {
  recordatorio_1: "dim_recordatorio_deuda",
  recordatorio_2: "dim_recordatorio_deuda",
  recordatorio_3: "dim_recordatorio_deuda",
  suspension:     "dim_aviso_suspension",
};

const plantilla = plantillas[d.tipo] || "dim_recordatorio_deuda";

const body = {
  messaging_product: "whatsapp",
  to: d.tel,
  type: "template",
  template: {
    name: plantilla,
    language: { code: "es" },
    components: [{
      type: "body",
      parameters: [
        { type: "text", text: d.nombre || "Cliente" },                          // {{1}} nombre
        { type: "text", text: String(d.diasVencido || 0) },                     // {{2}} días vencido
        { type: "text", text: "S/. " + parseFloat(d.deudaActual).toFixed(2) }, // {{3}} monto
      ]
    }]
  }
};

return [{ json: {
  phoneNumberId: PHONE_NUMBER_ID,
  token:         WABA_TOKEN,
  payload:       body,
  meta:          d,
}}];
